// Solution: 
function updateState(state, updates) {
  if (Object.keys(updates).length === 0) return state;
  if (Object.keys(state).length === Object.keys(updates).length) {
    let isEqual = true;
    for (let key in updates) {
      if (Object.is(state[key], updates[key])) continue;
      isEqual = false;
      break;
    }
    if (isEqual) return state;
  }
  return Object.assign({}, state, updates);
}

